  "multicastToUnicastConversionEnabled": True,
  "clientIsolationEnabled": True,
  "hideName": True,
  "uapsdEnabled": True,
  "basicDataRateKbpsByFrequencyGHz": {
    "5": 6000,
    "2.4": 2000
  },
  "clientFilteringPolicy": {
    "action": "ALLOW",
    "macAddressFilter": [
      "string"
    ]
  },
  "blackoutScheduleConfiguration": {
    "days": [
      {
        "type": "string",
        "day": "SUN"
      }
    ]
  }
